SELECT SUM(sz_population) AS total_population
FROM subzones
WHERE pa_id = 1;

SELECT sz_name
FROM subzones
WHERE sz_population = (SELECT MAX(sz_population) FROM subzones);

SELECT pa_population AS total_population
FROM planning_areas
WHERE pa_name = 'Ang Mo Kio';

SELECT pa_name
FROM planning_areas
ORDER BY pa_name ASC;

SELECT pa_name, pa_population
FROM planning_areas
ORDER BY pa_population DESC;

SELECT pa_name
FROM planning_areas
ORDER BY pa_name;
